class Solution:
    def threeSumClosest(self, nums: List[int], target: int) -> int:
        nums.sort()
        best = sum(nums[:3])
        for i in range(len(nums)-2):
            l, r = i+1, len(nums)-1
            while l < r:
                s = nums[i]+nums[l]+nums[r]
                if abs(s-target) < abs(best-target): best = s
                if s < target: l += 1
                elif s > target: r -= 1
                else: return s
        return best

